pub async fn get_invoice_by_id(
    req: HttpRequest,
    path: web::Path<InvoicePathParams>,
    pool: web::Data<PgPool>,
) -> Result<HttpResponse, Error> {
    let user = req.extensions()
        .get::<AuthenticatedUser>()
        .ok_or_else(|| actix_web::error::ErrorUnauthorized("User not authenticated"))?
        .clone();

    let invoice_id = path.invoice_id;

    let invoice = sqlx::query_as::<_, Invoice>(
        r#"
        SELECT 
            i.id,
            i.tenant_id,
            i.invoice_number,
            i.customer_id,
            c.name as customer_name,
            i.amount,
            i.currency,
            i.status,
            i.issue_date,
            i.due_date,
            i.created_by,
            i.created_at,
            i.updated_at
        FROM invoices i
        JOIN customers c ON i.customer_id = c.id
        WHERE i.id = $1
        "#
    )
    .bind(invoice_id)
    .fetch_optional(pool.get_ref())
    .await
    .map_err(|e| actix_web::error::ErrorInternalServerError(e))?
    .ok_or_else(|| actix_web::error::ErrorNotFound("Invoice not found"))?;

    if !check_tenant_access(&user, invoice.tenant_id) {
        return Err(actix_web::error::ErrorForbidden(
            "Access denied: Invoice belongs to different tenant"
        ));
    }

    if !check_resource_access(&user, &invoice) {
        return Err(actix_web::error::ErrorForbidden(
            "Access denied: Insufficient permissions to view this invoice"
        ));
    }

    let line_items = sqlx::query_as::<_, InvoiceLineItem>(
        r#"
        SELECT 
            id,
            invoice_id,
            description,
            quantity,
            unit_price,
            total
        FROM invoice_line_items
        WHERE invoice_id = $1
        ORDER BY id
        "#
    )
    .bind(invoice_id)
    .fetch_all(pool.get_ref())
    .await
    .map_err(|e| actix_web::error::ErrorInternalServerError(e))?;

    let can_edit = check_edit_permission(&user, &invoice);
    let can_delete = check_delete_permission(&user, &invoice);
    let editable_fields = get_editable_fields(&user, &invoice);

    let invoice_details = InvoiceDetails {
        invoice,
        line_items,
        can_edit,
        can_delete,
        editable_fields,
    };

    Ok(HttpResponse::Ok().json(invoice_details))
}

fn check_tenant_access(user: &AuthenticatedUser, resource_tenant_id: i64) -> bool {
    user.tenant_id == resource_tenant_id
}

fn check_resource_access(user: &AuthenticatedUser, invoice: &Invoice) -> bool {
    match user.role {
        UserRole::Admin => true,
        UserRole::Manager => {
            user.permissions.contains(&"invoices.read".to_string()) ||
            user.permissions.contains(&"invoices.read_all".to_string())
        },
        UserRole::User => {
            (user.permissions.contains(&"invoices.read".to_string()) && 
             invoice.created_by == user.user_id) ||
            user.permissions.contains(&"invoices.read_all".to_string())
        },
        UserRole::Viewer => {
            user.permissions.contains(&"invoices.read".to_string()) ||
            user.permissions.contains(&"invoices.read_all".to_string())
        },
    }
}

fn check_edit_permission(user: &AuthenticatedUser, invoice: &Invoice) -> bool {
    if invoice.status == "paid" || invoice.status == "cancelled" {
        return user.role == UserRole::Admin && 
               user.permissions.contains(&"invoices.edit_locked".to_string());
    }

    match user.role {
        UserRole::Admin => {
            user.permissions.contains(&"invoices.edit".to_string()) ||
            user.permissions.contains(&"invoices.edit_all".to_string())
        },
        UserRole::Manager => {
            user.permissions.contains(&"invoices.edit".to_string()) ||
            user.permissions.contains(&"invoices.edit_all".to_string())
        },
        UserRole::User => {
            user.permissions.contains(&"invoices.edit".to_string()) && 
            invoice.created_by == user.user_id
        },
        UserRole::Viewer => false,
    }
}

fn check_delete_permission(user: &AuthenticatedUser, invoice: &Invoice) -> bool {
    if invoice.status == "paid" {
        return false;
    }

    match user.role {
        UserRole::Admin => {
            user.permissions.contains(&"invoices.delete".to_string())
        },
        UserRole::Manager => {
            user.permissions.contains(&"invoices.delete".to_string()) &&
            invoice.status == "draft"
        },
        UserRole::User => {
            user.permissions.contains(&"invoices.delete".to_string()) &&
            invoice.created_by == user.user_id &&
            invoice.status == "draft"
        },
        UserRole::Viewer => false,
    }
}

fn get_editable_fields(user: &AuthenticatedUser, invoice: &Invoice) -> Vec<String> {
    let mut fields = Vec::new();

    if !check_edit_permission(user, invoice) {
        return fields;
    }

    let base_fields = vec![
        "customer_id",
        "issue_date",
        "due_date",
        "line_items",
    ];

    match user.role {
        UserRole::Admin => {
            fields.extend(base_fields);
            fields.push("invoice_number".to_string());
            fields.push("status".to_string());
            fields.push("amount".to_string());
            fields.push("currency".to_string());
            
            if user.permissions.contains(&"invoices.edit_locked".to_string()) {
                fields.push("created_by".to_string());
                fields.push("created_at".to_string());
            }
        },
        UserRole::Manager => {
            fields.extend(base_fields);
            
            if invoice.status == "draft" {
                fields.push("status".to_string());
            }
            
            if user.permissions.contains(&"invoices.edit_amount".to_string()) {
                fields.push("amount".to_string());
            }
        },
        UserRole::User => {
            if invoice.status == "draft" {
                fields.extend(base_fields);
            }
        },
        UserRole::Viewer => {},
    }

    if invoice.status == "paid" || invoice.status == "cancelled" {
        if user.role != UserRole::Admin || 
           !user.permissions.contains(&"invoices.edit_locked".to_string()) {
            return Vec::new();
        }
    }

    fields.into_iter().map(|s| s.to_string()).collect()
}